55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	  rune: 25,
68	  moonstone: 25,
69	};
70	
71	const basePremium = (item: Item): number =>
72	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
73	
74	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
75	
76	const groupByType = (items: Item[]): Map<string, Item[]> => {
77	  const groups = new Map<string, Item[]>();
78	  for (const item of items) {
79	    const existing = groups.get(item.type) ?? [];
80	    existing.push(item);
81	    groups.set(item.type, existing);
82	  }
83	  return groups;
84	};
85	
86	const sumBasePremiums = (items: Item[]): number =>
87	  items.reduce((sum, item) => sum + basePremium(item), 0);
88	
89	const groupTotal = (type: string, group: Item[]): number => {
90	  if (group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
91	    return COMPONENT_BLOCK_PRICE;
92	  }
93	  return sumBasePremiums(group);
94	};
95	
96	const policyBase = (items: Item[]): number => {
97	  let total = 0;
98	  for (const [type, group] of groupByType(items)) {
99	    total += groupTotal(type, group);
100	  }
101	  return total;
102	};
103	
104	const perItemSurcharge = (
105	  items: Item[],
106	  predicate: (item: Item) => boolean,
107	  rate: number,
108	): number =>
109	  items.reduce(
110	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
111	    0,
112	  );
113	
114	const isCursed = (item: Item): boolean => item.cursed === true;
115	
116	const isHighlyEnchanted = (item: Item): boolean =>
117	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
118	
119	const cursedSurcharge = (items: Item[]): number =>
120	  perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE);
121	
122	const highEnchantmentSurcharge = (items: Item[]): number =>
123	  perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);
124	
125	const quotePremium = (items: Item[]): number => {
126	  const base = policyBase(items);
127	  const surcharges =
128	    cursedSurcharge(items) +
129	    highEnchantmentSurcharge(items) +
130	    base * FIRST_INSURANCE_RATE;
131	  return Math.ceil(base + surcharges) + PROCESSING_FEE;
132	};
133	
134	export const processScenario = (scenario: Scenario): ScenarioOutput => {
135	  const step = scenario.steps[0] as QuoteStep;
136	  return { results: [{ premium: quotePremium(step.items) }] };
137	};
